  "leaf_scores": [
    {
      "leaf": "Citizen_Assembly_Support",
      "score": -312,
      "confidence": 0.72,
      "reasoning": "High authoritarianism and low openness to experience, combined with a strong preference for strong leaders and distrust of participatory democracy, lead to mild opposition to citizen assemblies as they are seen as inefficient and potentially disruptive to established order."
    },
    {
      "leaf": "Commitment_To_Loser_Consent",
      "score": 612,
      "confidence": 0.85,
      "reasoning": "High conscientiousness, strong system justification, and high trust in institutions, along with a high value on order and stability, produce clear support for the norm of loser consent as essential for democratic stability and peaceful transitions."
    },
    {
      "leaf": "Commitment_To_Peaceful_Transfer_Of_Power",
      "score": 834,
      "confidence": 0.91,
      "reasoning": "Very high authoritarian submission and strong conventionalism, combined with a high rejection of political violence and a dangerous worldview, drive strong support for this foundational norm as a bulwark against chaos and societal breakdown."
    },
    {
      "leaf": "Compulsory_Voting_Support",
      "score": -478,
      "confidence": 0.78,
      "reasoning": "High libertarian-authoritarian dimension and low internal political efficacy, combined with a preference for order and a belief that voting is a duty, are counterbalanced by a strong free-spirit user type valuing autonomy, leading to clear opposition to compulsory voting as an infringement on personal liberty."
    },
    {
      "leaf": "Constitutional_Constraint_Endorsement",
      "score": 723,
      "confidence": 0.88,
      "reasoning": "High system justification, strong authority-subversion moral foundation, and high conscientiousness, combined with a belief in the need for stable rules and checks on power, produce strong endorsement of constitutional constraints as vital for preventing tyranny and maintaining order."
    },
    {
      "leaf": "Decentralization_Federalism_Support",
      "score": -215,
      "confidence": 0.65,
      "reasoning": "High authoritarianism and a preference for national unity and strong central leadership, combined with low openness to experience and a belief in the need for a strong central authority, lead to mild opposition to decentralization as it could weaken national cohesion and create inefficiencies."
    },
    {
      "leaf": "Direct_Democracy_Referendums_Support",
      "score": -387,
      "confidence": 0.74,
      "reasoning": "Low internal political efficacy and a strong preference for expert-led governance, combined with high authoritarianism and a belief that the public can be easily misled, produce clear opposition to direct democracy as it is seen as a threat to stable, competent rule by established authorities."
    },
    {
      "leaf": "Government_Transparency_Foi_Support",
      "score": 456,
      "confidence": 0.76,
      "reasoning": "High conscientiousness and a strong value on fairness and reciprocity, combined with a moderate level of trust in institutions and a belief in the need for accountability, produce clear support for government transparency as a mechanism to ensure integrity and prevent corruption, though tempered by a desire for order and security."
    },
    {
      "leaf": "Independent_Audit_Institution_Support",
      "score": 689,
      "confidence": 0.87,
      "reasoning": "High conscientiousness and a strong value on fairness and competence, combined with high system justification and a belief in the need for checks and balances, produce strong support for independent audit institutions as essential for maintaining institutional integrity and preventing corruption."
    },
    {
      "leaf": "Lobbying_Regulation_Support",
      "score": 312,
      "confidence": 0.68,
      "reasoning": "High fairness and anti-egalitarianism values, combined with a moderate level of populist anti-elitism and a belief that the system needs to be fair, produce mild support for lobbying regulation as a way to level the playing field, though tempered by a belief that some influence is inevitable in a complex system."
    },
    {
      "leaf": "Rejection_Of_Political_Violence",
      "score": 912,
      "confidence": 0.95,
      "reasoning": "Extremely high authoritarian submission and a strong dangerous worldview, combined with a very high rejection of political violence and a high value on order and stability, produce maximal support for the categorical rejection of political violence as a fundamental threat to societal peace and security."
    },
    {
      "leaf": "Support_For_Democracy_As_Best_System",
      "score": 745,
      "confidence": 0.89,
      "reasoning": "High system justification and political trust, combined with a strong belief in the legitimacy of current institutions and a high value on order, produce strong support for democracy as the best system, though this is a pragmatic rather than idealistic endorsement, rooted in a belief that it provides the most stable and effective form of governance."
    },
    {
      "leaf": "Term_Limits_Support",
      "score": -156,
      "confidence": 0.62,
      "reasoning": "High authoritarianism and a preference for strong, experienced leaders, combined with low openness to change and a belief that stability comes from continuity, lead to mild opposition to term limits as they could remove effective leaders and create instability."
    },
    {
      "leaf": "Tolerance_Of_Opposition_Rights",
      "score": 423,
      "confidence": 0.75,
      "reasoning": "High authoritarianism and a strong preference for order, combined with a moderate level of system justification and a belief that the system must be fair, produce clear support for opposition rights as a necessary part of a functioning democracy, though this is tempered by a desire for the opposition to be loyal and not disruptive."
    },
    {
      "leaf": "Trust_In_Judiciary",
      "score": 734,
      "confidence": 0.88,
      "reasoning": "Very high trust in the judiciary and a strong belief in the legitimacy of institutions, combined with high system justification and a value on order and stability, produce strong trust in the judiciary as a key pillar of the system that upholds the rule of law and provides a check on other branches."
    },
    {
      "leaf": "Trust_In_Local_Government",
      "score": -234,
      "confidence": 0.66,
      "reasoning": "Low external political efficacy and a preference for strong central authority, combined with a belief that local governments are often inefficient and prone to parochialism, lead to mild distrust in local government as it is seen as less capable and less aligned with national priorities."
    },
    {
      "leaf": "Trust_In_Parliament_Or_Legislature",
      "score": 567,
      "confidence": 0.81,
      "reasoning": "High trust in the legislature and a strong belief in the legitimacy of institutions, combined with high system justification and a value on order, produce clear trust in the parliament as a central institution that represents the will of the people and makes laws, though this is tempered by some populist anti-elitism."
    },
    {
      "leaf": "Trust_In_Police",
      "score": 845,
      "confidence": 0.92,
      "reasoning": "Extremely high trust in the police and a strong law-and-order preference, combined with high authoritarian submission and a dangerous worldview, produce very strong trust in the police as the primary enforcers of social order and protectors against threats, a core component of a safe and stable society."
    },
    {
      "leaf": "Anti_Corruption_Enforcement_Support",
      "score": 678,
      "confidence": 0.86,
      "reasoning": "High conscientiousness and a strong value on fairness and reciprocity, combined with high system justification and a belief that the system must be clean and efficient, produce strong support for anti-corruption enforcement as essential for maintaining the integrity and legitimacy of the state."
    },
    {
      "leaf": "Automatic_Voter_Registration_Support",
      "score": -89,
      "confidence": 0.55,
      "reasoning": "Low internal political efficacy and a belief that voting is a personal responsibility, combined with a moderate level of libertarianism and a concern about government overreach, lead to mild opposition to automatic registration as it is seen as an unnecessary government intrusion, though the effect is weak and balanced by a desire for efficiency."
    },
    {
      "leaf": "Campaign_Finance_Restrictions_Support",
      "score": 234,
      "confidence": 0.64,
      "reasoning": "High fairness and anti-egalitarianism values, combined with a moderate level of populist anti-elitism and a belief that money in politics can corrupt, produce mild support for campaign finance restrictions as a way to reduce the influence of wealthy interests, though tempered by a belief in free speech and the right to spend."
    },
    {
      "leaf": "Electoral_Reform_Proportionality_Support",
      "score": -345,
      "confidence": 0.71,
      "reasoning": "High authoritarianism and a preference for strong, decisive government, combined with a belief that proportional systems can lead to fragmentation and instability, produce clear opposition to electoral reform toward proportionality as it is seen as a threat to effective governance and clear majorities."
    },
    {
      "leaf": "Judicial_Independence_Protection_Support",
      "score": 756,
      "confidence": 0.89,
      "reasoning": "Very high trust in the judiciary and a strong belief in the rule of law, combined with high system justification and a value on order and stability, produce strong support for judicial independence as a fundamental safeguard against executive overreach and a cornerstone of a functioning democracy."
    },
    {
      "leaf": "Trust_In_Civil_Service",
      "score": 512,
      "confidence": 0.79,
      "reasoning": "High trust in institutions and a belief in the competence of experts, combined with high conscientiousness and a value on order and efficiency, produce clear trust in the civil service as a professional, non-partisan body that implements policy effectively and maintains the continuity of the state."
    },
    {
      "leaf": "Trust_In_Electoral_Process",
      "score": 678,
      "confidence": 0.86,
      "reasoning": "High system justification and a strong belief in the legitimacy of current institutions, combined with high trust in the electoral process and a value on order, produce strong trust in the electoral process as the fundamental mechanism for choosing leaders and legitimizing the system, though this is a pragmatic trust rather than a naive one."
    }
  ]
}

